package jaas.command.org.apache.karaf.jaas.command;

@ Command ( scope = "jaas" , name = "update" , description = "Apply pending modification on the edited JAAS Realm" ) @ Service public class UpdateCommand extends JaasCommandSupport { @ Override public Object execute ( ) throws Exception { JaasRealm realm = ( JaasRealm ) session . get ( JAAS_REALM ) ; AppConfigurationEntry entry = ( AppConfigurationEntry ) session . get ( JAAS_ENTRY ) ; if ( realm == null || entry == null ) { System . err . println ( "No JAAS Realm/Login Module selected" ) ; return null ; } BackingEngine engine = getBackingEngine ( entry ) ; if ( engine == null ) { System . err . println ( "Can't update the JAAS realm (no backing engine service registered)" ) ; return null ; } return doExecute ( engine ) ; } @ Override protected Object doExecute ( BackingEngine engine ) throws Exception { @ SuppressWarnings ( "unchecked" ) Queue < ? extends JaasCommandSupport > commands = ( Queue < ? extends JaasCommandSupport > ) session . get ( JAAS_CMDS ) ; if ( commands == null || commands . isEmpty ( ) ) { System . err . println ( "No JAAS pending modification" ) ; return null ; } while ( ! commands . isEmpty ( ) ) { Object obj = commands . remove ( ) ; if ( obj instanceof JaasCommandSupport ) { ( ( JaasCommandSupport ) obj ) . doExecute ( engine ) ; } } session . put ( JAAS_REALM , null ) ; session . put ( JAAS_ENTRY , null ) ; session . put ( JAAS_CMDS , new LinkedList < JaasCommandSupport > ( ) ) ; return null ; } }